const { DynamoDBClient, UpdateItemCommand, GetItemCommand } = require('@aws-sdk/client-dynamodb');
const { marshall, unmarshall } = require('@aws-sdk/util-dynamodb');
const https = require('https');

const dynamoClient = new DynamoDBClient({
  region: process.env.AWS_REGION,
  maxAttempts: 3,
});

const ORDERS_TABLE = process.env.ORDERS_TABLE_NAME;
const PAYMENT_API_URL = process.env.PAYMENT_API_URL;
const PAYMENT_API_TIMEOUT_MS = parseInt(process.env.PAYMENT_API_TIMEOUT_MS || '5000', 10);
const ALLOWED_PAYMENT_HOST = process.env.ALLOWED_PAYMENT_HOST;

const agent = new https.Agent({
  keepAlive: true,
  maxSockets: 50,
  timeout: PAYMENT_API_TIMEOUT_MS,
});

exports.handler = async (event) => {
  if (!ORDERS_TABLE || !PAYMENT_API_URL || !ALLOWED_PAYMENT_HOST) {
    const msg = 'Missing required environment variables: ORDERS_TABLE_NAME, PAYMENT_API_URL, ALLOWED_PAYMENT_HOST';
    console.error(msg);
    throw new Error(msg);
  }

  const batchItemFailures = [];

  const processingPromises = event.Records.map(async (record) => {
    const messageId = record.messageId;
    let order;

    try {
      order = JSON.parse(record.body);
    } catch (parseError) {
      console.error(JSON.stringify({
        level: 'ERROR',
        message: 'Failed to parse SQS message body',
        messageId,
        error: parseError.message,
      }));
      batchItemFailures.push({ itemIdentifier: messageId });
      return;
    }

    try {
      validateOrder(order);

      const isDuplicate = await checkIdempotency(order.orderId);
      if (isDuplicate) {
        console.info(JSON.stringify({
          level: 'INFO',
          message: 'Duplicate order detected, skipping',
          orderId: order.orderId,
          messageId,
        }));
        return;
      }

      await updateOrderStatus(order.orderId, 'PROCESSING');

      const paymentResult = await processPayment(order);

      if (paymentResult.success) {
        await updateOrderStatus(order.orderId, 'PAYMENT_COMPLETED', {
          transactionId: paymentResult.transactionId,
          processedAt: new Date().toISOString(),
        });

        console.info(JSON.stringify({
          level: 'INFO',
          message: 'Order processed successfully',
          orderId: order.orderId,
          messageId,
        }));
      } else {
        await updateOrderStatus(order.orderId, 'PAYMENT_FAILED', {
          failureReason: sanitizeForLog(paymentResult.reason || 'Unknown'),
          failedAt: new Date().toISOString(),
        });

        console.warn(JSON.stringify({
          level: 'WARN',
          message: 'Payment failed for order',
          orderId: order.orderId,
          messageId,
        }));

        batchItemFailures.push({ itemIdentifier: messageId });
      }
    } catch (processingError) {
      console.error(JSON.stringify({
        level: 'ERROR',
        message: 'Error processing order',
        orderId: order?.orderId,
        messageId,
        errorType: processingError.name,
        error: sanitizeForLog(processingError.message),
      }));

      try {
        if (order?.orderId) {
          await updateOrderStatus(order.orderId, 'ERROR', {
            errorMessage: sanitizeForLog(processingError.message),
            errorAt: new Date().toISOString(),
          });
        }
      } catch (updateError) {
        console.error(JSON.stringify({
          level: 'ERROR',
          message: 'Failed to update order status to ERROR',
          orderId: order?.orderId,
          error: sanitizeForLog(updateError.message),
        }));
      }

      batchItemFailures.push({ itemIdentifier: messageId });
    }
  });

  await Promise.allSettled(processingPromises);

  return { batchItemFailures };
};

function validateOrder(order) {
  if (!order || typeof order !== 'object') {
    throw new ValidationError('Order must be a non-null object');
  }
  if (!order.orderId || typeof order.orderId !== 'string') {
    throw new ValidationError('Order must have a valid string orderId');
  }
  if (order.orderId.length > 128 || !/^[a-zA-Z0-9\-_]+$/.test(order.orderId)) {
    throw new ValidationError('Order ID contains invalid characters or exceeds max length');
  }
  if (!order.amount || typeof order.amount !== 'number' || order.amount <= 0) {
    throw new ValidationError('Order must have a positive numeric amount');
  }
  if (order.amount > 1000000) {
    throw new ValidationError('Order amount exceeds maximum allowed value');
  }
  if (!order.currency || typeof order.currency !== 'string' || !/^[A-Z]{3}$/.test(order.currency)) {
    throw new ValidationError('Order must have a valid 3-letter currency code');
  }
  if (!order.customerId || typeof order.customerId !== 'string') {
    throw new ValidationError('Order must have a valid customerId');
  }
  if (order.customerId.length > 128 || !/^[a-zA-Z0-9\-_]+$/.test(order.customerId)) {
    throw new ValidationError('Customer ID contains invalid characters or exceeds max length');
  }
}

class ValidationError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ValidationError';
  }
}

async function checkIdempotency(orderId) {
  const params = {
    TableName: ORDERS_TABLE,
    Key: marshall({ orderId }),
    ProjectionExpression: 'orderId, #s',
    ExpressionAttributeNames: { '#s': 'status' },
  };

  const result = await dynamoClient.send(new GetItemCommand(params));

  if (result.Item) {
    const item = unmarshall(result.Item);
    return ['PAYMENT_COMPLETED', 'PROCESSING'].includes(item.status);
  }

  return false;
}

async function updateOrderStatus(orderId, status, additionalAttributes = {}) {
  let updateExpression = 'SET #s = :status, updatedAt = :updatedAt';
  const expressionAttributeNames = { '#s': 'status' };
  const expressionAttributeValues = {
    ':status': { S: status },
    ':updatedAt': { S: new Date().toISOString() },
  };

  Object.entries(additionalAttributes).forEach(([key, value]) => {
    const safeKey = key.replace(/[^a-zA-Z0-9]/g, '');
    const attrPlaceholder = `#attr_${safeKey}`;
    const valPlaceholder = `:val_${safeKey}`;
    updateExpression += `, ${attrPlaceholder} = ${valPlaceholder}`;
    expressionAttributeNames[attrPlaceholder] = safeKey;
    expressionAttributeValues[valPlaceholder] = { S: String(value).substring(0, 1000) };
  });

  const params = {
    TableName: ORDERS_TABLE,
    Key: marshall({ orderId }),
    UpdateExpression: updateExpression,
    ExpressionAttributeNames: expressionAttributeNames,
    ExpressionAttributeValues: expressionAttributeValues,
    ConditionExpression: 'attribute_exists(orderId) OR attribute_not_exists(orderId)',
  };

  await dynamoClient.send(new UpdateItemCommand(params));
}

async function processPayment(order) {
  const url = new URL(PAYMENT_API_URL);

  if (url.protocol !== 'https:') {
    throw new Error('Payment API URL must use HTTPS');
  }

  if (url.hostname !== ALLOWED_PAYMENT_HOST) {
    throw new Error('Payment API URL hostname is not in the allowed list');
  }

  const paymentPayload = JSON.stringify({
    orderId: order.orderId,
    amount: order.amount,
    currency: order.currency,
    customerId: order.customerId,
    idempotencyKey: `payment-${order.orderId}`,
  });

  return new Promise((resolve, reject) => {
    const timeout = setTimeout(() => {
      req.destroy();
      reject(new Error(`Payment API request timed out after ${PAYMENT_API_TIMEOUT_MS}ms`));
    }, PAYMENT_API_TIMEOUT_MS);

    const options = {
      hostname: url.hostname,
      port: url.port || 443,
      path: url.pathname,
      method: 'POST',
      agent,
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(paymentPayload),
        'X-Idempotency-Key': `payment-${order.orderId}`,
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      const maxResponseSize = 1024 * 1024; // 1MB limit

      res.on('data', (chunk) => {
        data += chunk;
        if (data.length > maxResponseSize) {
          clearTimeout(timeout);
          req.destroy();
          reject(new Error('Payment API response exceeded maximum size'));
        }
      });

      res.on('end', () => {
        clearTimeout(timeout);
        try {
          const response = JSON.parse(data);

          if (res.statusCode >= 200 && res.statusCode < 300) {
            resolve({
              success: true,
              transactionId: typeof response.transactionId === 'string'
                ? response.transactionId.substring(0, 256)
                : 'unknown',
            });
          } else if (res.statusCode >= 400 && res.statusCode < 500) {
            resolve({
              success: false,
              reason: typeof response.message === 'string'
                ? response.message.substring(0, 500)
                : 'Client error',
            });
          } else {
            reject(new Error(`Payment API returned status ${res.statusCode}`));
          }
        } catch (parseError) {
          reject(new Error('Failed to parse payment API response'));
        }
      });
    });

    req.on('error', (error) => {
      clearTimeout(timeout);
      reject(new Error(`Payment API request failed: ${error.message}`));
    });

    req.write(paymentPayload);
    req.end();
  });
}

function sanitizeForLog(value) {
  if (typeof value !== 'string') {
    return String(value || '').substring(0, 500);
  }
  return value
    .replace(/[\r\n]/g, ' ')
    .replace(/[^\x20-\x7E]/g, '')
    .substring(0, 500);
}